-- Gym Master - Base profesional de ejercicios para rutinas/RAG
-- Feature: feature/rutinas-exercise-knowledge-base-seed
-- Date: 2026-05-26
-- Purpose:
--   1) Enriquecer public.ejercicio con metadatos de programación de entrenamiento.
--   2) Crear reglas parametrizadas por objetivo/nivel para generación dinámica.
--   3) Crear base de media de ejercicios para Cloudinary/YouTube futura.
--   4) Cargar seed profesional para objetivos que no tenían ejercicios.
--   5) Mantener compatibilidad con el frontend actual y con generar_rutina_socio().

BEGIN;

-- ============================================================
-- 1. Extensión defensiva de public.ejercicio
-- ============================================================
ALTER TABLE public.ejercicio
  ADD COLUMN IF NOT EXISTS nombre_en text,
  ADD COLUMN IF NOT EXISTS descripcion text,
  ADD COLUMN IF NOT EXISTS descripcion_en text,
  ADD COLUMN IF NOT EXISTS tipo_ejercicio text,
  ADD COLUMN IF NOT EXISTS patron_movimiento text,
  ADD COLUMN IF NOT EXISTS equipamiento text,
  ADD COLUMN IF NOT EXISTS dificultad integer,
  ADD COLUMN IF NOT EXISTS orden_sugerido integer,
  ADD COLUMN IF NOT EXISTS series_sugeridas text,
  ADD COLUMN IF NOT EXISTS repeticiones_sugeridas text,
  ADD COLUMN IF NOT EXISTS descanso_sugerido_seg integer,
  ADD COLUMN IF NOT EXISTS rpe_sugerido text,
  ADD COLUMN IF NOT EXISTS intensidad text,
  ADD COLUMN IF NOT EXISTS frecuencia_semanal_sugerida integer,
  ADD COLUMN IF NOT EXISTS contraindicaciones text,
  ADD COLUMN IF NOT EXISTS video_youtube_url text,
  ADD COLUMN IF NOT EXISTS youtube_video_id text,
  ADD COLUMN IF NOT EXISTS imagen_origen text,
  ADD COLUMN IF NOT EXISTS cloudinary_public_id text,
  ADD COLUMN IF NOT EXISTS media_actualizada_en timestamp without time zone,
  ADD COLUMN IF NOT EXISTS activo boolean DEFAULT true NOT NULL;

CREATE INDEX IF NOT EXISTS idx_ejercicio_objetivo_nivel_gm_activo
  ON public.ejercicio (id_objetivo, id_nivel, id_gm, activo);

CREATE INDEX IF NOT EXISTS idx_ejercicio_tipo_ejercicio
  ON public.ejercicio (tipo_ejercicio);

CREATE INDEX IF NOT EXISTS idx_ejercicio_video_youtube_url
  ON public.ejercicio (video_youtube_url)
  WHERE video_youtube_url IS NOT NULL;

COMMENT ON COLUMN public.ejercicio.video_youtube_url IS 'URL opcional de YouTube recomendada para explicar la técnica del ejercicio. Curación manual futura.';
COMMENT ON COLUMN public.ejercicio.cloudinary_public_id IS 'Public ID de Cloudinary si la imagen/GIF fue migrada a almacenamiento propio.';
COMMENT ON COLUMN public.ejercicio.imagen_origen IS 'Origen de la imagen principal: cloudinary, externa, fallback, local u otro.';

-- Normalización básica de ejercicios existentes.
UPDATE public.ejercicio
SET
  nombre_en = COALESCE(nombre_en, nombre_ejercicio),
  descripcion = COALESCE(descripcion, 'Ejercicio existente normalizado para la base profesional de rutinas.'),
  tipo_ejercicio = COALESCE(tipo_ejercicio, CASE
    WHEN id_objetivo = 4 THEN 'fuerza'
    WHEN id_objetivo = 2 THEN 'hipertrofia_densidad'
    WHEN id_objetivo = 3 THEN 'metabolico'
    ELSE 'hipertrofia'
  END),
  patron_movimiento = COALESCE(patron_movimiento, CASE id_gm
    WHEN 1 THEN 'empuje horizontal'
    WHEN 2 THEN 'tracción'
    WHEN 3 THEN 'dominante de rodilla/cadera'
    WHEN 4 THEN 'flexión de codo'
    WHEN 5 THEN 'extensión de codo'
    WHEN 6 THEN 'empuje vertical/estabilidad escapular'
    WHEN 7 THEN 'core anti-movimiento'
    WHEN 8 THEN 'extensión/abducción de cadera'
    ELSE 'general'
  END),
  equipamiento = COALESCE(equipamiento, 'máquina/mancuernas/barra según disponibilidad'),
  dificultad = COALESCE(dificultad, id_nivel),
  orden_sugerido = COALESCE(orden_sugerido, CASE WHEN id_gm IN (1,2,3,6,8) THEN 1 ELSE 3 END),
  series_sugeridas = COALESCE(series_sugeridas, CASE
    WHEN id_objetivo = 4 THEN '5'
    WHEN id_objetivo IN (6,9,10) THEN '2-3'
    ELSE '3-4'
  END),
  repeticiones_sugeridas = COALESCE(repeticiones_sugeridas, CASE
    WHEN id_objetivo = 4 THEN '3-5'
    WHEN id_objetivo IN (2,6,7,9,10) THEN '10-15'
    WHEN id_objetivo IN (3,5) THEN '12-20'
    ELSE '8-12'
  END),
  descanso_sugerido_seg = COALESCE(descanso_sugerido_seg, CASE
    WHEN id_objetivo = 4 THEN 180
    WHEN id_objetivo IN (3,5,10) THEN 45
    WHEN id_objetivo IN (6,7,9) THEN 75
    ELSE 90
  END),
  rpe_sugerido = COALESCE(rpe_sugerido, CASE
    WHEN id_objetivo = 4 THEN '8-9'
    WHEN id_objetivo IN (6,9,10) THEN '5-7'
    ELSE '7-8'
  END),
  intensidad = COALESCE(intensidad, CASE
    WHEN id_objetivo = 4 THEN 'alta'
    WHEN id_objetivo IN (6,9,10) THEN 'baja-moderada'
    ELSE 'moderada'
  END),
  frecuencia_semanal_sugerida = COALESCE(frecuencia_semanal_sugerida, CASE WHEN id_nivel = 1 THEN 1 ELSE 2 END),
  imagen = COALESCE(NULLIF(imagen, ''), '/images/exercises/gym-master-exercise-fallback.svg'),
  imagen_origen = COALESCE(imagen_origen, CASE
    WHEN imagen ILIKE 'https://res.cloudinary.com/%' THEN 'cloudinary'
    WHEN imagen ILIKE 'http://%' OR imagen ILIKE 'https://%' THEN 'externa'
    WHEN imagen ILIKE '/images/%' THEN 'fallback'
    ELSE 'local'
  END),
  activo = COALESCE(activo, true),
  actualizado_en = now();

-- ============================================================
-- 2. Reglas de generación por objetivo/nivel
-- ============================================================
CREATE TABLE IF NOT EXISTS public.rutina_generacion_regla (
  id integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  id_objetivo integer NOT NULL REFERENCES public.objetivo(id_objetivo),
  id_nivel integer NOT NULL REFERENCES public.nivel(id_nivel),
  series_sugeridas text NOT NULL,
  repeticiones_sugeridas text NOT NULL,
  descanso_seg integer NOT NULL,
  rpe_sugerido text NOT NULL,
  intensidad text NOT NULL,
  frecuencia_semanal_sugerida integer NOT NULL DEFAULT 1,
  cardio_recomendado text,
  criterio_programacion text NOT NULL,
  advertencia text,
  activo boolean NOT NULL DEFAULT true,
  creado_en timestamp without time zone NOT NULL DEFAULT now(),
  actualizado_en timestamp without time zone NOT NULL DEFAULT now()
);

CREATE UNIQUE INDEX IF NOT EXISTS rutina_generacion_regla_unq_objetivo_nivel
  ON public.rutina_generacion_regla (id_objetivo, id_nivel);

COMMENT ON TABLE public.rutina_generacion_regla IS 'Reglas base de programación por objetivo y nivel para generación dinámica de rutinas y futuro RAG coach.';

