INSERT INTO public.rutina_generacion_regla (
  id_objetivo, id_nivel, series_sugeridas, repeticiones_sugeridas, descanso_seg,
  rpe_sugerido, intensidad, frecuencia_semanal_sugerida, cardio_recomendado,
  criterio_programacion, advertencia, actualizado_en
)
SELECT
  id_objetivo, id_nivel, series_sugeridas, repeticiones_sugeridas, descanso_seg,
  rpe_sugerido, intensidad, frecuencia_semanal_sugerida, cardio_recomendado,
  criterio_programacion, advertencia, now()
FROM seed_reglas
ON CONFLICT (id_objetivo, id_nivel)
DO UPDATE SET
  series_sugeridas = EXCLUDED.series_sugeridas,
  repeticiones_sugeridas = EXCLUDED.repeticiones_sugeridas,
  descanso_seg = EXCLUDED.descanso_seg,
  rpe_sugerido = EXCLUDED.rpe_sugerido,
  intensidad = EXCLUDED.intensidad,
  frecuencia_semanal_sugerida = EXCLUDED.frecuencia_semanal_sugerida,
  cardio_recomendado = EXCLUDED.cardio_recomendado,
  criterio_programacion = EXCLUDED.criterio_programacion,
  advertencia = EXCLUDED.advertencia,
  actualizado_en = now();

-- ============================================================
-- 3. Base para media de ejercicios / Cloudinary / YouTube
-- ============================================================
CREATE TABLE IF NOT EXISTS public.ejercicio_media (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  id_ejercicio integer NOT NULL REFERENCES public.ejercicio(id_ejercicio) ON DELETE CASCADE,
  tipo_media text NOT NULL DEFAULT 'imagen',
  origen text NOT NULL DEFAULT 'fallback',
  url text NOT NULL,
  cloudinary_public_id text,
  youtube_url text,
  youtube_video_id text,
  titulo text,
  descripcion text,
  es_principal boolean NOT NULL DEFAULT true,
  activo boolean NOT NULL DEFAULT true,
  creado_en timestamp without time zone NOT NULL DEFAULT now(),
  actualizado_en timestamp without time zone NOT NULL DEFAULT now(),
  CONSTRAINT ejercicio_media_tipo_chk CHECK (tipo_media IN ('imagen','gif','video','youtube','thumbnail')),
  CONSTRAINT ejercicio_media_origen_chk CHECK (origen IN ('cloudinary','youtube','externa','local','fallback'))
);

CREATE INDEX IF NOT EXISTS idx_ejercicio_media_ejercicio_activo
  ON public.ejercicio_media (id_ejercicio, activo);

CREATE UNIQUE INDEX IF NOT EXISTS ejercicio_media_unq_principal
  ON public.ejercicio_media (id_ejercicio, tipo_media)
  WHERE es_principal = true AND activo = true;

COMMENT ON TABLE public.ejercicio_media IS 'Banco de media por ejercicio. Base para migrar imágenes a Cloudinary y asociar links de YouTube por ejercicio.';

-- Insertar una media principal para ejercicios que ya tienen imagen y aún no tienen registro.
INSERT INTO public.ejercicio_media (id_ejercicio, tipo_media, origen, url, titulo, descripcion, es_principal, activo)
SELECT
  e.id_ejercicio,
  CASE WHEN e.imagen ILIKE '%.gif%' THEN 'gif' ELSE 'imagen' END,
  COALESCE(e.imagen_origen, 'fallback'),
  e.imagen,
  e.nombre_ejercicio,
  'Media principal creada automáticamente desde la columna ejercicio.imagen.',
  true,
  true
FROM public.ejercicio e
WHERE e.imagen IS NOT NULL
  AND NOT EXISTS (
    SELECT 1
    FROM public.ejercicio_media em
    WHERE em.id_ejercicio = e.id_ejercicio
      AND em.tipo_media IN ('imagen','gif')
      AND em.es_principal = true
      AND em.activo = true
  );

-- ============================================================
