), inserted AS (
  INSERT INTO public.ejercicio (
    nombre_ejercicio, nombre_en, id_nivel, id_objetivo, id_gm, imagen,
    descripcion, tipo_ejercicio, patron_movimiento, equipamiento, dificultad,
    orden_sugerido, series_sugeridas, repeticiones_sugeridas, descanso_sugerido_seg,
    rpe_sugerido, intensidad, video_youtube_url, imagen_origen, activo, creado_en, actualizado_en
  )
  SELECT
    s.nombre_ejercicio, s.nombre_en, s.id_nivel, s.id_objetivo, s.id_gm, s.imagen,
    s.descripcion, s.tipo_ejercicio, s.patron_movimiento, s.equipamiento, s.dificultad,
    s.orden_sugerido, s.series_sugeridas, s.repeticiones_sugeridas, s.descanso_sugerido_seg,
    s.rpe_sugerido, s.intensidad, s.video_youtube_url, 'fallback', true, now(), now()
  FROM seed_ejercicios s
  WHERE NOT EXISTS (
    SELECT 1
    FROM public.ejercicio e
    WHERE lower(trim(e.nombre_ejercicio)) = lower(trim(s.nombre_ejercicio))
      AND e.id_objetivo = s.id_objetivo
      AND e.id_nivel = s.id_nivel
      AND e.id_gm = s.id_gm
  )
  RETURNING id_ejercicio, nombre_ejercicio, imagen, imagen_origen
)
INSERT INTO public.ejercicio_media (id_ejercicio, tipo_media, origen, url, titulo, descripcion, es_principal, activo)
SELECT
  id_ejercicio,
  'imagen',
  COALESCE(imagen_origen, 'fallback'),
  imagen,
  nombre_ejercicio,
  'Fallback inicial. Reemplazar por GIF/imagen Cloudinary curada desde el panel de media de ejercicios.',
  true,
  true
FROM inserted;

-- ============================================================
-- 5. RPC de generación enriquecida y backward-compatible
-- ============================================================
CREATE OR REPLACE FUNCTION public.generar_rutina_socio(
  p_id_socio uuid,
  p_id_objetivo integer DEFAULT NULL::integer,
  p_id_nivel integer DEFAULT NULL::integer,
  p_dias integer DEFAULT NULL::integer
) RETURNS TABLE(id_rutina integer, rutina jsonb)
LANGUAGE plpgsql SECURITY DEFINER
SET search_path TO 'public'
AS $$
DECLARE
  v_objetivo              int;
  v_nivel                 int;
  v_dias                  int;
  v_inicio                date;
  v_fin                   date;
  v_week                  int;
  v_series                text;
  v_reps                  text;
  v_descanso              int;
  v_rpe                   text;
  v_intensidad            text;
  v_criterio              text;
  v_advertencia           text;
  v_ejercicios_por_dia    int;
  v_grupos_por_dia        int := 2;
  v_last_used             int[] := ARRAY[]::int[];
  v_rotation              int[];
  v_rotation_len          int;
  v_last_main             int := NULL;
  v_primary_gm            int;
  v_secondary_gm          int;
  v_dias_array            jsonb := '[]'::jsonb;
  v_dia_json              jsonb;
  v_day_json1             jsonb;
  v_day_json2             jsonb;
  v_rutina_json           jsonb;
  v_id_rutina             int;
  v_pos                   int;
  v_primary_pos           int;
  v_first_count           int;
  v_second_count          int;
  i                       int;
  k_ventana_no_repetir    interval := interval '45 days';
BEGIN
  SELECT
    COALESCE(p_id_objetivo, s.objetivo),
    COALESCE(p_id_nivel,    s.nivel),
    COALESCE(p_dias,        s.dias_por_semana)
  INTO v_objetivo, v_nivel, v_dias
  FROM socio s
  WHERE s.id_socio = p_id_socio;

  IF v_objetivo IS NULL OR v_nivel IS NULL OR v_dias IS NULL THEN
    RAISE EXCEPTION 'Faltan datos (objetivo, nivel o dias_por_semana) para el socio %', p_id_socio;
  END IF;

  IF v_dias < 1 OR v_dias > 6 THEN
    RAISE EXCEPTION 'La cantidad de días debe estar entre 1 y 6. Valor recibido: %', v_dias;
  END IF;

  SELECT
    r.series_sugeridas,
    r.repeticiones_sugeridas,
    r.descanso_seg,
    r.rpe_sugerido,
    r.intensidad,
    r.criterio_programacion,
    r.advertencia
  INTO v_series, v_reps, v_descanso, v_rpe, v_intensidad, v_criterio, v_advertencia
  FROM public.rutina_generacion_regla r
  WHERE r.id_objetivo = v_objetivo
    AND r.id_nivel = v_nivel
    AND r.activo = true
  LIMIT 1;

  IF v_series IS NULL THEN
    IF v_objetivo = 4 THEN
      v_series := '5'; v_reps := '3-5'; v_descanso := 180; v_rpe := '8-9'; v_intensidad := 'alta';
    ELSIF v_objetivo = 2 THEN
      v_series := '3'; v_reps := '12-15'; v_descanso := 60; v_rpe := '7-8'; v_intensidad := 'moderada-alta';
    ELSE
      v_series := '4'; v_reps := '8-12'; v_descanso := 90; v_rpe := '7-9'; v_intensidad := 'moderada';
    END IF;
    v_criterio := 'Regla fallback de generación por compatibilidad.';
    v_advertencia := 'Ajustar si aparece dolor, fatiga excesiva o deterioro técnico.';
  END IF;

  CASE v_nivel
    WHEN 1 THEN v_ejercicios_por_dia := 6;
    WHEN 2 THEN v_ejercicios_por_dia := 7;
    ELSE         v_ejercicios_por_dia := 8;
  END CASE;

  v_first_count  := CEIL(v_ejercicios_por_dia / 2.0);
  v_second_count := v_ejercicios_por_dia - v_first_count;

  v_inicio := (current_date + (8 - extract(isodow from current_date))::int)::date;
  IF v_inicio = current_date AND extract(isodow from current_date) = 1 THEN
    v_inicio := current_date;
  END IF;

  v_fin  := v_inicio + (v_dias - 1);
  v_week := EXTRACT(week FROM v_inicio)::int;

  -- Evita repetir exactamente la rutina activa/reciente del socio.
  SELECT array_agg((e->>'id')::int)
  INTO v_last_used
  FROM (
    SELECT rutina_desc
    FROM rutina
    WHERE id_socio = p_id_socio
      AND creado_en >= (now()::date - k_ventana_no_repetir)
    ORDER BY creado_en DESC
    LIMIT 1
  ) r
  CROSS JOIN LATERAL jsonb_array_elements(r.rutina_desc->'dias') d
  CROSS JOIN LATERAL jsonb_array_elements(d->'ejercicios') e;

  IF v_last_used IS NULL THEN
    v_last_used := ARRAY[]::int[];
  END IF;

  SELECT array_agg(gm.id_gm ORDER BY gm.id_gm)
  INTO v_rotation
  FROM grupo_muscular gm
  WHERE gm.id_gm BETWEEN 1 AND 8
    AND EXISTS (
      SELECT 1
      FROM ejercicio ej
      WHERE ej.id_gm = gm.id_gm
        AND ej.id_objetivo = v_objetivo
        AND ej.id_nivel = v_nivel
        AND COALESCE(ej.activo, true) = true
    );

  v_rotation_len := COALESCE(array_length(v_rotation, 1), 0);

  IF v_rotation_len = 0 THEN
    RAISE EXCEPTION 'No hay ejercicios definidos para objetivo % y nivel %', v_objetivo, v_nivel;
  END IF;

  IF v_rotation_len < 2 THEN
    v_grupos_por_dia := 1;
  END IF;

  FOR i IN 1..v_dias LOOP
    IF v_last_main IS NULL THEN
      v_primary_gm := v_rotation[1];
    ELSE
      v_pos := COALESCE(array_position(v_rotation, v_last_main), 1);
      IF v_pos = v_rotation_len THEN
        v_primary_gm := v_rotation[1];
      ELSE
        v_primary_gm := v_rotation[v_pos + 1];
      END IF;
    END IF;

    v_last_main := v_primary_gm;

    IF v_grupos_por_dia = 2 THEN
      v_primary_pos := COALESCE(array_position(v_rotation, v_primary_gm), 1);
      IF v_primary_pos = v_rotation_len THEN
        v_secondary_gm := v_rotation[1];
      ELSE
        v_secondary_gm := v_rotation[v_primary_pos + 1];
      END IF;
    ELSE
      v_secondary_gm := v_primary_gm;
    END IF;

    WITH pool AS (
      SELECT
        e.id_ejercicio AS id,
        e.nombre_ejercicio AS nombre,
        e.id_gm AS grupo,
        gm.nombre_gp AS grupo_nombre,
        e.imagen,
        e.tipo_ejercicio,
        e.patron_movimiento,
        e.equipamiento,
        e.video_youtube_url,
        e.orden_sugerido,
        COALESCE(e.series_sugeridas, v_series) AS series,
        COALESCE(e.repeticiones_sugeridas, v_reps) AS reps,
        COALESCE(e.descanso_sugerido_seg, v_descanso) AS descanso_seg,
        COALESCE(e.rpe_sugerido, v_rpe) AS rpe,
        COALESCE(e.intensidad, v_intensidad) AS intensidad
      FROM ejercicio e
      JOIN grupo_muscular gm ON gm.id_gm = e.id_gm
      WHERE e.id_objetivo = v_objetivo
        AND e.id_nivel = v_nivel
        AND e.id_gm = v_primary_gm
        AND COALESCE(e.activo, true) = true
        AND NOT (e.id_ejercicio = ANY (v_last_used))
      ORDER BY COALESCE(e.orden_sugerido, 99), random()
      LIMIT v_first_count
    ),
    fallback AS (
      SELECT
        e.id_ejercicio AS id,
        e.nombre_ejercicio AS nombre,
        e.id_gm AS grupo,
        gm.nombre_gp AS grupo_nombre,
        e.imagen,
        e.tipo_ejercicio,
        e.patron_movimiento,
        e.equipamiento,
        e.video_youtube_url,
        e.orden_sugerido,
        COALESCE(e.series_sugeridas, v_series) AS series,
        COALESCE(e.repeticiones_sugeridas, v_reps) AS reps,
        COALESCE(e.descanso_sugerido_seg, v_descanso) AS descanso_seg,
        COALESCE(e.rpe_sugerido, v_rpe) AS rpe,
        COALESCE(e.intensidad, v_intensidad) AS intensidad
      FROM ejercicio e
      JOIN grupo_muscular gm ON gm.id_gm = e.id_gm
      WHERE e.id_objetivo = v_objetivo
        AND e.id_nivel = v_nivel
        AND e.id_gm = v_primary_gm
        AND COALESCE(e.activo, true) = true
      ORDER BY COALESCE(e.orden_sugerido, 99), random()
      LIMIT v_first_count
    )
    SELECT COALESCE(jsonb_agg(
      jsonb_build_object(
        'id', id,
        'nombre', nombre,
        'grupo', grupo,
        'grupo_nombre', grupo_nombre,
        'imagen', imagen,
        'tipo_ejercicio', tipo_ejercicio,
        'patron_movimiento', patron_movimiento,
        'equipamiento', equipamiento,
        'video_youtube_url', video_youtube_url,
        'orden_sugerido', orden_sugerido,
        'series', series,
        'reps', reps,
        'descanso_seg', descanso_seg,
        'rpe', rpe,
        'intensidad', intensidad
      )
    ), '[]'::jsonb)
    INTO v_day_json1
    FROM (
      SELECT * FROM pool
      UNION ALL
      SELECT * FROM fallback WHERE NOT EXISTS (SELECT 1 FROM pool)
    ) x;

    IF v_grupos_por_dia = 2 THEN
      WITH pool2 AS (
        SELECT
          e.id_ejercicio AS id,
          e.nombre_ejercicio AS nombre,
          e.id_gm AS grupo,
          gm.nombre_gp AS grupo_nombre,
          e.imagen,
          e.tipo_ejercicio,
          e.patron_movimiento,
          e.equipamiento,
          e.video_youtube_url,
          e.orden_sugerido,
          COALESCE(e.series_sugeridas, v_series) AS series,
          COALESCE(e.repeticiones_sugeridas, v_reps) AS reps,
          COALESCE(e.descanso_sugerido_seg, v_descanso) AS descanso_seg,
          COALESCE(e.rpe_sugerido, v_rpe) AS rpe,
          COALESCE(e.intensidad, v_intensidad) AS intensidad
        FROM ejercicio e
        JOIN grupo_muscular gm ON gm.id_gm = e.id_gm
        WHERE e.id_objetivo = v_objetivo
          AND e.id_nivel = v_nivel
          AND e.id_gm = v_secondary_gm
          AND COALESCE(e.activo, true) = true
          AND NOT (e.id_ejercicio = ANY (v_last_used))
        ORDER BY COALESCE(e.orden_sugerido, 99), random()
        LIMIT v_second_count
      ),
      fallback2 AS (
        SELECT
          e.id_ejercicio AS id,
          e.nombre_ejercicio AS nombre,
          e.id_gm AS grupo,
          gm.nombre_gp AS grupo_nombre,
          e.imagen,
          e.tipo_ejercicio,
          e.patron_movimiento,
          e.equipamiento,
          e.video_youtube_url,
          e.orden_sugerido,
          COALESCE(e.series_sugeridas, v_series) AS series,
          COALESCE(e.repeticiones_sugeridas, v_reps) AS reps,
          COALESCE(e.descanso_sugerido_seg, v_descanso) AS descanso_seg,
          COALESCE(e.rpe_sugerido, v_rpe) AS rpe,
          COALESCE(e.intensidad, v_intensidad) AS intensidad
        FROM ejercicio e
        JOIN grupo_muscular gm ON gm.id_gm = e.id_gm
        WHERE e.id_objetivo = v_objetivo
          AND e.id_nivel = v_nivel
          AND e.id_gm = v_secondary_gm
          AND COALESCE(e.activo, true) = true
        ORDER BY COALESCE(e.orden_sugerido, 99), random()
        LIMIT v_second_count
      )
      SELECT COALESCE(jsonb_agg(
        jsonb_build_object(
          'id', id,
          'nombre', nombre,
          'grupo', grupo,
          'grupo_nombre', grupo_nombre,
          'imagen', imagen,
          'tipo_ejercicio', tipo_ejercicio,
          'patron_movimiento', patron_movimiento,
          'equipamiento', equipamiento,
          'video_youtube_url', video_youtube_url,
          'orden_sugerido', orden_sugerido,
          'series', series,
          'reps', reps,
          'descanso_seg', descanso_seg,
          'rpe', rpe,
          'intensidad', intensidad
        )
      ), '[]'::jsonb)
      INTO v_day_json2
      FROM (
        SELECT * FROM pool2
        UNION ALL
        SELECT * FROM fallback2 WHERE NOT EXISTS (SELECT 1 FROM pool2)
      ) y;
    ELSE
      v_day_json2 := '[]'::jsonb;
    END IF;

    v_dia_json := COALESCE(v_day_json1, '[]'::jsonb) || COALESCE(v_day_json2, '[]'::jsonb);

    SELECT COALESCE(
      array_cat(v_last_used, COALESCE(array_agg((e->>'id')::int), ARRAY[]::int[])),
      v_last_used
    )
    INTO v_last_used
    FROM jsonb_array_elements(v_dia_json) e;

    v_dias_array := v_dias_array || jsonb_build_array(
      jsonb_build_object(
        'dia', i,
        'fecha', (v_inicio + (i - 1))::text,
        'grupos',
          (SELECT jsonb_agg(gm.nombre_gp)
           FROM grupo_muscular gm
           WHERE gm.id_gm IN (v_primary_gm, v_secondary_gm)),
        'ejercicios', v_dia_json
      )
    );
  END LOOP;

  v_rutina_json := jsonb_build_object(
    'socio_id', p_id_socio::text,
    'objetivo', v_objetivo,
    'nivel', v_nivel,
    'dias_por_semana', v_dias,
    'periodo', jsonb_build_object('inicio', v_inicio::text, 'fin', v_fin::text),
    'dias', v_dias_array,
    'metadata', jsonb_build_object(
      'generated_at', now() AT TIME ZONE 'UTC',
      'rules_version', 3,
      'grupos_por_dia', v_grupos_por_dia,
      'criterio_programacion', v_criterio,
      'advertencia', v_advertencia,
      'ventana_no_repetir_dias', 45
    )
  );

  INSERT INTO rutina (id_socio, rutina_desc, semana, nombre, actualizado_en)
  VALUES (
    p_id_socio,
    v_rutina_json,
    v_week,
    'Rutina auto ' || to_char(now(), 'YYYY-MM-DD HH24:MI'),
    now()
  )
  ON CONFLICT (id_socio, semana)
  DO UPDATE SET
    rutina_desc = EXCLUDED.rutina_desc,
    actualizado_en = now(),
    nombre = EXCLUDED.nombre
  RETURNING rutina.id_rutina INTO v_id_rutina;

  RETURN QUERY SELECT v_id_rutina, v_rutina_json;
END;
$$;

COMMIT;
